import React from 'react';
import { useNavigate } from 'react-router-dom';
import { StarDisplay } from '../shared/StarRating';

const CATEGORY_ICONS = {
  Electrician: '⚡', Plumber: '🔧', Carpenter: '🪚',
  Painter: '🎨', Cleaner: '🧹', ACTechnician: '❄️',
};

export default function ProviderCard({ provider, showBookBtn = true }) {
  const navigate = useNavigate();
  const user = provider.user || {};
  const initials = user.name?.split(' ').map(n => n[0]).join('').slice(0, 2).toUpperCase();

  return (
    <div className="provider-card animate-fade" onClick={() => navigate(`/provider/${provider._id}`)}>
      {/* Header */}
      <div style={{ display: 'flex', gap: 14, alignItems: 'flex-start', marginBottom: 14 }}>
        <div style={{ position: 'relative', flexShrink: 0 }}>
          {user.avatar ? (
            <img src={user.avatar} alt={user.name}
              style={{ width: 52, height: 52, borderRadius: '50%', objectFit: 'cover', border: '2px solid var(--border-light)' }} />
          ) : (
            <div style={{
              width: 52, height: 52, borderRadius: '50%', background: 'var(--accent-dim)',
              display: 'flex', alignItems: 'center', justifyContent: 'center',
              color: 'var(--accent)', fontWeight: 700, fontSize: 18, fontFamily: 'var(--font-display)',
            }}>{initials}</div>
          )}
          <span style={{
            position: 'absolute', bottom: 0, right: -2,
            width: 14, height: 14, borderRadius: '50%',
            background: provider.availability?.isAvailable ? 'var(--success)' : 'var(--text-muted)',
            border: '2px solid var(--bg-card)',
          }} />
        </div>

        <div style={{ flex: 1, minWidth: 0 }}>
          <div style={{ fontWeight: 700, fontSize: 15, fontFamily: 'var(--font-display)', display: 'flex', alignItems: 'center', gap: 6 }}>
            {user.name}
            {provider.verificationStatus === 'approved' && (
              <span style={{ color: 'var(--accent)', fontSize: 13 }} title="Verified">✓</span>
            )}
          </div>
          <div style={{ fontSize: 13, color: 'var(--text-secondary)', display: 'flex', alignItems: 'center', gap: 6, marginTop: 2 }}>
            <span>{CATEGORY_ICONS[provider.serviceCategory]}</span>
            <span>{provider.serviceCategory}</span>
          </div>
        </div>

        {provider.distance !== undefined && (
          <div style={{ fontSize: 12, color: 'var(--text-muted)', flexShrink: 0, textAlign: 'right' }}>
            📍 {provider.distance.toFixed(1)} km
          </div>
        )}
      </div>

      {/* Skills */}
      <div style={{ display: 'flex', flexWrap: 'wrap', gap: 6, marginBottom: 12 }}>
        {(provider.skills || []).slice(0, 3).map(skill => (
          <span key={skill} className="badge badge-muted">{skill}</span>
        ))}
        {provider.skills?.length > 3 && (
          <span className="badge badge-muted">+{provider.skills.length - 3}</span>
        )}
      </div>

      {/* Stats Row */}
      <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', paddingTop: 12, borderTop: '1px solid var(--border)' }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
          <StarDisplay rating={provider.rating?.average || 0} count={provider.rating?.count || 0} />
        </div>

        <div style={{ display: 'flex', gap: 12, fontSize: 12, color: 'var(--text-secondary)' }}>
          <span>💼 {provider.experience}y exp</span>
          <span>✅ {provider.completedJobs || 0} jobs</span>
        </div>
      </div>

      {/* Price + Book */}
      <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginTop: 14 }}>
        <div>
          <span style={{ fontSize: 13, color: 'var(--text-muted)' }}>Starting from</span>
          <div style={{ fontWeight: 700, fontSize: 18, fontFamily: 'var(--font-display)', color: 'var(--success)' }}>
            ₹{provider.priceRange?.min}
            <span style={{ fontSize: 12, fontWeight: 400, color: 'var(--text-muted)' }}> – ₹{provider.priceRange?.max}</span>
          </div>
        </div>

        {showBookBtn && (
          <button
            className="btn btn-primary btn-sm"
            onClick={e => { e.stopPropagation(); navigate(`/book/${provider._id}`); }}
          >
            Book Now
          </button>
        )}
      </div>
    </div>
  );
}
